#include<bits/stdc++.h>
#define p(x,y) ((x-1)*n+y)
using namespace std;
vector<pair<long long,long long>> mp[750010];
long long dis[750010],n,s,t;
bool vis[750010];
void dijkstra()
{
    priority_queue<pair<long long,long long>> q;
    q.push({0,s});
    memset(dis,0x3f,sizeof(dis));
    dis[s]=0;
    while(!q.empty())
    {
        long long t=q.top().second;
        q.pop();
        if(vis[t])
        {
            continue;
        }
        vis[t]=true;
        for(auto i:mp[t])
        {
            long long v=i.first,val=i.second;
            if(dis[v]>dis[t]+val)
            {
                dis[v]=dis[t]+val;
                q.push({-dis[v],v});
            }
        }
    }
}
int main()
{
    scanf("%lld",&n);
    s=0;
    t=(n+1)*(n+1)+1;
    for(long long i=1;i<=n+1;i++)
    {
        for(long long j=1;j<=n;j++)
        {
            long long x;
            scanf("%lld",&x);
            if(i==1)
            {
                mp[s].push_back({p(i,j),x});
            }
            else if(i==n+1)
            {
                mp[p(i-1,j)].push_back({t,x});
            }
            else
            {
                mp[p(i-1,j)].push_back({p(i,j),x});
            }
        }
    }
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<=n+1;j++)
        {
            long long x;
            scanf("%lld",&x);
            if(j==1)
            {
                mp[p(i,j)].push_back({t,x});
            }
            else if(j==n+1)
            {
                mp[s].push_back({p(i,j-1),x});
            }
            else
            {
                mp[p(i,j)].push_back({p(i,j-1),x});
            }
        }
    }
    for(long long i=1;i<=n+1;i++)
    {
        for(long long j=1;j<=n;j++)
        {
            long long x;
            scanf("%lld",&x);
            if(i==1)
            {
                mp[p(i,j)].push_back({s,x});
            }
            else if(i==n+1)
            {
                mp[t].push_back({p(i-1,j),x});
            }
            else
            {
                mp[p(i,j)].push_back({p(i-1,j),x});
            }
        }
    }
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<=n+1;j++)
        {
            long long x;
            scanf("%lld",&x);
            if(j==1)
            {
                mp[t].push_back({p(i,j),x});
            }
            else if(j==n+1)
            {
                mp[p(i,j-1)].push_back({s,x});
            }
            else
            {
                mp[p(i,j-1)].push_back({p(i,j),x});
            }
        }
    }
    dijkstra();
    printf("%lld",dis[t]);
    return 0;
}
